    "speaker": "めたん",
    "text": "従来のサイトは、リンクをクリックするたびにサーバーから新しいHTMLが届いていましたの。",
    "speakerColor": "#d6336c",
    "sceneId": 6,
    "sceneTitle": "SPA時代の到来",
